effect.shader:
vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

void main() {
    vec2 st = acLayerNorm;

    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);

    if( type==1 ) {
        st.y = 1.-st.y;
        st.y += offset;
    } else {
        st.x = 1.-st.x;
        st.x += offset;
    }

    vec4 color = texture2DCv(inputImg.texture,l2s(st));

    vec4 result;
    if( blendMode==1 ) {
        result = vec4((texColor.rgb/texColor.a)*color.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-color.rgb)),1.0) * texColor.a;
    } else if( blendMode==3 ) {
        result = texColor * (1.-color.a) + color;
    } else if( blendMode==4 ) {
        result = color * (1.-texColor.a) + texColor;
    } else {
        result = color;
    }

    gl_FragColor = mix(texColor,result,alpha);
}
